def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import re
    A_NS_URI = 'http://schemas.openxmlformats.org/drawingml/2006/main'

    # The four exact items we expect to be converted to numbered list
    TARGET_TEXTS = [
        'Have students complete 1-2 questions on unseen texts per week rather than completing an entire paper.',
        'Students need to submit these responses to their teacher and have them marked.',
        'You need to build upon your knowledge and see as many unseen texts between now and the Trial and then again in preparation for the HSC.',
        'If you give yourself the opportunity to see and complete a range of short answer responses, the benefits will be clear.'
    ]

    def normalize_text(text: str) -> str:
        if text is None:
            return ''
        return ' '.join(text.strip().split())

    def strip_leading_list_token(text: str) -> str:
        if not text:
            return ''
        pattern = r'^\s*(?:\(\d+\)|\d+[\.\-)]|[A-Za-z][\.\-)]|[ivxlcdmIVXLCDM]+[\.\-)])\s*'
        return re.sub(pattern, '', text)

    def looks_manually_numbered(text: str) -> bool:
        if not text:
            return False
        return re.match(r'^\s*(?:\(\d+\)|\d+[\.\-)]|[A-Za-z][\.\-)]|[ivxlcdmIVXLCDM]+[\.\-)])\s+', text) is not None

    def is_numbered(paragraph) -> bool:
        # True numbered list when a:buAutoNum is set at paragraph level or inherited
        p = paragraph._p
        pPr = getattr(p, 'pPr', None)
        if pPr is not None and pPr.find(f'{{{A_NS_URI}}}buAutoNum') is not None:
            return True
        txBody = p.getparent()
        if txBody is None:
            return False
        lstStyle = txBody.find(f'{{{A_NS_URI}}}lstStyle')
        if lstStyle is None:
            return False
        level = getattr(paragraph, 'level', 0) or 0
        lvl_idx = min(level + 1, 9)
        lvl_pPr = lstStyle.find(f'{{{A_NS_URI}}}lvl{lvl_idx}pPr')
        if lvl_pPr is not None and lvl_pPr.find(f'{{{A_NS_URI}}}buAutoNum') is not None:
            return True
        defPPr = lstStyle.find(f'{{{A_NS_URI}}}defPPr')
        if defPPr is not None and defPPr.find(f'{{{A_NS_URI}}}buAutoNum') is not None:
            return True
        return False

    # Open the modified presentation only; we just need to verify conversion
    mod = Presentation(modified_ppt_path)

    # Map normalized target text -> original text and converted flag
    norm_to_original = {normalize_text(t): t for t in TARGET_TEXTS}
    converted = {t: False for t in TARGET_TEXTS}

    for slide in mod.slides:
        for shape in slide.shapes:
            if not getattr(shape, 'has_text_frame', False):
                continue
            for para in shape.text_frame.paragraphs:
                raw = para.text or ''
                norm = normalize_text(strip_leading_list_token(raw))
                if norm in norm_to_original:
                    if is_numbered(para) or looks_manually_numbered(raw):
                        converted[norm_to_original[norm]] = True

    num_converted = sum(1 for v in converted.values() if v)
    score = num_converted / 4.0

    if num_converted == 4:
        return ("All 4 items converted to numbered list.", 1.0)
    else:
        missing = [t for t, ok in converted.items() if not ok]
        return (f"{num_converted}/4 items converted to numbered list. Missing: {missing}", score)

def compute_score() -> tuple[str, float]:
    # Check ppt_diff for slide 19
    slide_id_19 = None
    for s in ppt_diff.added_slides + ppt_diff.removed_slides:
        # Defensive: don't allow slide 19 to be added/removed
        if s.slide_number == 19:
            return ("Slide 19 was added or removed, which is extraneous.", 0.0)
    for s1, s2 in ppt_diff.modified_slides:
        # Find slide 19
        if s1.slide_number == 19:
            slide_id_19 = s1.slide_id
            # If notes, title, layout, or element count changed, that's extraneous
            if (s1.title != s2.title) or (s1.layout_type != s2.layout_type) or (s1.notes != s2.notes):
                return ("Title, layout, or notes of slide 19 modified, which is extraneous.", 0.0)
            # If element_count differs by more than the plausible change for list conversion, penalize
            if abs(s1.element_count - s2.element_count) > 2:
                return ("Element count on slide 19 changed in an unexpected way.", 0.0)
    # Check for new/removed animations or transitions on slide 19
    for ae in ppt_diff.added_animations + ppt_diff.removed_animations:
        if ae.slide_id == slide_id_19:
            return ("Animations were added or removed on slide 19.", 0.0)
    for (ae1, ae2) in ppt_diff.modified_animations:
        if ae1.slide_id == slide_id_19:
            return ("Animations were modified on slide 19.", 0.0)
    for tr in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        if tr.slide_id == slide_id_19:
            return ("Transitions were added or removed on slide 19.", 0.0)
    for (tr1, tr2) in ppt_diff.modified_transitions:
        if tr1.slide_id == slide_id_19:
            return ("Transitions were modified on slide 19.", 0.0)
    return ("No extraneous changes detected on slide 19.", 1.0)

def compute_score() -> tuple[str, float]:
    # Slides are 1-indexed
    bad_changes = []
    # Check slides added/removed/modified
    for s in ppt_diff.added_slides:
        if s.slide_number != 19:
            bad_changes.append(f"Added slide {s.slide_number}")
    for s in ppt_diff.removed_slides:
        if s.slide_number != 19:
            bad_changes.append(f"Removed slide {s.slide_number}")
    for s1, s2 in ppt_diff.modified_slides:
        if s1.slide_number != 19:
            bad_changes.append(f"Modified slide {s1.slide_number}")
    # Animations
    for ae in ppt_diff.added_animations + ppt_diff.removed_animations:
        if ae.slide_id is not None:
            # Try to get slide number from slide_id
            # We'll be conservative: if slide_id doesn't match slide 19, penalize
            if not (hasattr(ae, 'slide_number') and ae.slide_number == 19):
                bad_changes.append("Animation added/removed on non-target slide")
    for (ae1, ae2) in ppt_diff.modified_animations:
        if hasattr(ae1, 'slide_number') and ae1.slide_number != 19:
            bad_changes.append("Animation modified on non-target slide")
    # Transitions
    for tr in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        if hasattr(tr, 'slide_number') and tr.slide_number != 19:
            bad_changes.append("Transition added/removed on non-target slide")
    for (tr1, tr2) in ppt_diff.modified_transitions:
        if hasattr(tr1, 'slide_number') and tr1.slide_number != 19:
            bad_changes.append("Transition modified on non-target slide")
    if bad_changes:
        return ("Extraneous changes to other slides: " + ", ".join(bad_changes), 0.0)
    return ("No changes to slides other than 19.", 1.0)
